import{_ as a,o as n,c as p,ae as e}from"./chunks/framework.DTwQaIIa.js";const u=JSON.parse('{"title":"强化流程","description":"","frontmatter":{},"headers":[],"relativePath":"modules/strengthen/process.md","filePath":"modules/strengthen/process.md"}'),l={name:"modules/strengthen/process.md"};function i(t,s,c,r,o,d){return n(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="强化流程" tabindex="-1">强化流程 <a class="header-anchor" href="#强化流程" aria-label="Permalink to &quot;强化流程&quot;">​</a></h1><p>这一页拆解 EmakiStrengthen 的完整强化流程：从打开界面到强化完成，中间经历了哪些步骤，成功率怎么算，失败了会怎样，数据存在哪里，以及物品刷新是怎么工作的。</p><h2 id="完整强化流程" tabindex="-1">完整强化流程 <a class="header-anchor" href="#完整强化流程" aria-label="Permalink to &quot;完整强化流程&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 打开 GUI</span></span>
<span class="line"><span>   └── 玩家执行 /estrengthen open 或通过其他方式打开强化界面</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 放入装备</span></span>
<span class="line"><span>   └── 把装备放进 target_item 槽位（槽位 13）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 配方解析</span></span>
<span class="line"><span>   ├── StrengthenRecipeResolver 遍历所有已加载配方</span></span>
<span class="line"><span>   ├── 按 match 规则逐一匹配（source_types → source_ids → source_patterns → slot_groups → lore_contains → stats_any）</span></span>
<span class="line"><span>   ├── 匹配成功 → 加载对应配方，显示当前星级和下一阶段信息</span></span>
<span class="line"><span>   └── 无匹配 → 提示装备不可强化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 放入材料</span></span>
<span class="line"><span>   └── 把材料放进 material_input 槽位（槽位 19/20/29/30）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 材料计划解析</span></span>
<span class="line"><span>   ├── MaterialPlanResolver 读取当前星级阶段的 materials 需求</span></span>
<span class="line"><span>   ├── 逐一检查材料槽位中的物品是否匹配</span></span>
<span class="line"><span>   ├── 匹配成功 → 标记材料为可消耗，更新预览</span></span>
<span class="line"><span>   └── 匹配失败 → 提示缺少材料</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 预览计算</span></span>
<span class="line"><span>   ├── 计算强化后的属性变化</span></span>
<span class="line"><span>   ├── 计算成功率（含锻印加成）</span></span>
<span class="line"><span>   ├── 计算经济费用</span></span>
<span class="line"><span>   └── 在 preview_display 槽位（槽位 15）显示预览</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 确认强化</span></span>
<span class="line"><span>   └── 玩家点击 confirm 按钮（槽位 40）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>8. 执行强化尝试</span></span>
<span class="line"><span>   ├── ChanceCalculator 计算最终成功率</span></span>
<span class="line"><span>   ├── 随机判定成功/失败</span></span>
<span class="line"><span>   ├── 成功 → 进入成功流程</span></span>
<span class="line"><span>   └── 失败 → 进入失败流程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>9. 成功流程</span></span>
<span class="line"><span>   ├── 提升星级</span></span>
<span class="line"><span>   ├── StrengthenSnapshotBuilder 重建强化层</span></span>
<span class="line"><span>   ├── 写入新的 stats 和 attributes</span></span>
<span class="line"><span>   ├── 更新 structured_presentation</span></span>
<span class="line"><span>   ├── 执行 success_actions</span></span>
<span class="line"><span>   └── 重置锻印等级为 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>10. 失败流程</span></span>
<span class="line"><span>    ├── 检查是否有保护道具</span></span>
<span class="line"><span>    ├── 有保护 → 消耗保护道具，不降星</span></span>
<span class="line"><span>    ├── 无保护 → 根据配置降星或产生裂痕（crack）</span></span>
<span class="line"><span>    ├── 锻印等级 +1（不超过 max_temper）</span></span>
<span class="line"><span>    └── 执行 failure_actions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>11. PDC 写入</span></span>
<span class="line"><span>    ├── StrengthenPdcAttributeWriter 更新 PDC 数据</span></span>
<span class="line"><span>    ├── 写入当前星级、锻印等级、裂痕等级等</span></span>
<span class="line"><span>    └── 更新审计数据</span></span>
<span class="line"><span></span></span>
<span class="line"><span>12. 经济扣费</span></span>
<span class="line"><span>    └── StrengthenEconomyService 按 cost_formula 扣除费用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>13. 消耗材料</span></span>
<span class="line"><span>    └── 从材料槽位中扣除对应数量的材料</span></span>
<span class="line"><span></span></span>
<span class="line"><span>14. 广播</span></span>
<span class="line"><span>    ├── 星级 ≥ local_stars → 局部广播（半径内玩家可见）</span></span>
<span class="line"><span>    └── 星级 ≥ global_stars → 全局广播（全服可见）</span></span></code></pre></div><p>注意步骤 12 和 13 的顺序：先扣钱再扣材料。不管成功还是失败，材料和费用都会被消耗。</p><h2 id="chancecalculator-成功率计算" tabindex="-1">ChanceCalculator 成功率计算 <a class="header-anchor" href="#chancecalculator-成功率计算" aria-label="Permalink to &quot;ChanceCalculator 成功率计算&quot;">​</a></h2><h3 id="基础公式" tabindex="-1">基础公式 <a class="header-anchor" href="#基础公式" aria-label="Permalink to &quot;基础公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最终成功率 = min(base_rate + temper_bonus, success_chance_cap)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>从哪来</th></tr></thead><tbody><tr><td><code>base_rate</code></td><td>基础成功率</td><td>配方的 <code>success_rates</code>，没配就用全局 <code>config.yml</code> 的</td></tr><tr><td><code>temper_bonus</code></td><td>锻印加成</td><td><code>当前锻印等级 × temper_chance_bonus_per_level</code></td></tr><tr><td><code>success_chance_cap</code></td><td>成功率上限</td><td>配方的 <code>limits.success_chance_cap</code></td></tr></tbody></table><h3 id="计算示例" tabindex="-1">计算示例 <a class="header-anchor" href="#计算示例" aria-label="Permalink to &quot;计算示例&quot;">​</a></h3><p>假设：</p><ul><li>目标星级 7 的基础成功率 = 40%</li><li>当前锻印等级 = 5</li><li>每级锻印加成 = 1.5%</li><li>成功率上限 = 95%</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>temper_bonus = 5 × 1.5 = 7.5%</span></span>
<span class="line"><span>最终成功率 = min(40 + 7.5, 95) = 47.5%</span></span></code></pre></div><p>也就是说，这个玩家之前失败了 5 次积累了 5 级锻印，让成功率从 40% 提升到了 47.5%。</p><h3 id="锻印-temper-机制" tabindex="-1">锻印（Temper）机制 <a class="header-anchor" href="#锻印-temper-机制" aria-label="Permalink to &quot;锻印（Temper）机制&quot;">​</a></h3><p>锻印是一种失败补偿机制，核心思路是&quot;越失败越容易成功&quot;：</p><ul><li>每次强化失败，锻印等级 +1（不超过 <code>max_temper</code>）</li><li>每级锻印加 <code>temper_chance_bonus_per_level</code> 的成功率</li><li>强化成功后，锻印等级归零</li><li>锻印等级存在装备的 PDC 数据里，跟着装备走</li></ul><p>这样设计是为了避免玩家连续失败太多次后彻底放弃。锻印积累到一定程度，成功率会明显提升，给玩家一个&quot;再试一次&quot;的动力。</p><h2 id="失败处理" tabindex="-1">失败处理 <a class="header-anchor" href="#失败处理" aria-label="Permalink to &quot;失败处理&quot;">​</a></h2><h3 id="有保护道具" tabindex="-1">有保护道具 <a class="header-anchor" href="#有保护道具" aria-label="Permalink to &quot;有保护道具&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>强化失败</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>检测到保护道具</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>消耗保护道具</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>星级不变，不产生裂痕</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>锻印等级 +1</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>执行 failure_actions</span></span></code></pre></div><p>保护道具的价值在于：虽然这次失败了，但至少不会降星。而且锻印还是会 +1，所以下次成功率更高。</p><h3 id="无保护道具" tabindex="-1">无保护道具 <a class="header-anchor" href="#无保护道具" aria-label="Permalink to &quot;无保护道具&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>强化失败</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>无保护道具</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>根据配置执行惩罚：</span></span>
<span class="line"><span>    ├── 降星（星级 -1，最低降至 0）</span></span>
<span class="line"><span>    └── 产生裂痕（crack_level +1）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>锻印等级 +1</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>执行 failure_actions</span></span></code></pre></div><p>裂痕（crack）是装备的一种损伤状态，可能影响装备的属性或外观展示。管理员可以用 <code>/estrengthen clearcrack</code> 命令清除裂痕，也可以设计游戏内的修复机制。</p><h2 id="数据存储" tabindex="-1">数据存储 <a class="header-anchor" href="#数据存储" aria-label="Permalink to &quot;数据存储&quot;">​</a></h2><p>强化数据通过 PDC（PersistentDataContainer）存储在装备物品上。这意味着数据跟着物品走，不依赖外部数据库。详细的数据结构和读取方式参见 <a href="./api.html">API 与集成</a> 页面。</p><h2 id="strengthenrefreshservice" tabindex="-1">StrengthenRefreshService <a class="header-anchor" href="#strengthenrefreshservice" aria-label="Permalink to &quot;StrengthenRefreshService&quot;">​</a></h2><p>和 EmakiForge 的物品刷新服务类似，StrengthenRefreshService 解决的是&quot;配方改了之后，已强化装备的展示怎么跟着更新&quot;的问题。</p><h3 id="触发时机" tabindex="-1">触发时机 <a class="header-anchor" href="#触发时机" aria-label="Permalink to &quot;触发时机&quot;">​</a></h3><ul><li>玩家打开背包时</li><li>玩家手持物品切换时</li><li>管理员执行 <code>/estrengthen refresh</code> 命令时</li><li>配方资源重载后</li></ul><h3 id="刷新流程" tabindex="-1">刷新流程 <a class="header-anchor" href="#刷新流程" aria-label="Permalink to &quot;刷新流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>检测物品是否包含 strengthen layer 数据</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>读取物品 PDC 中的 strengthen audit map</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>获取 recipe_id，查找对应配方</span></span>
<span class="line"><span>    ├── 配方不存在 → 跳过（可能是配方被删了）</span></span>
<span class="line"><span>    └── 配方存在 ↓</span></span>
<span class="line"><span>用当前配方定义计算新签名</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>和物品上存储的 materials_signature 比较</span></span>
<span class="line"><span>    ├── 签名一致 → 不需要刷新</span></span>
<span class="line"><span>    └── 签名不一致 → 执行刷新</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    根据 current_star 获取对应星级阶段的 structured_presentation</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    通过 AssemblyService 重建物品展示</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    更新 materials_signature</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">提示</p><p>刷新服务只更新展示层（名称、Lore），不会改变已经写入的属性数值。如果你需要重置属性，用 <code>/estrengthen setstar</code> 命令重新设定星级，这会触发完整的属性重写。</p></div>`,34)])])}const b=a(l,[["render",i]]);export{u as __pageData,b as default};
